# Basic Unit Testing Example with pytest
# File: test_calculator.py

import pytest

# Function under test
def calculate_discount(price, discount_percent):
    """Calculate discounted price"""
    if price < 0:
        raise ValueError("Price cannot be negative")
    if discount_percent < 0 or discount_percent > 100:
        raise ValueError("Discount must be between 0 and 100")
    discount_amount = price * (discount_percent / 100)
    return price - discount_amount

# Test cases for quality verification
class TestCalculateDiscount:
    def test_standard_discount(self):
        assert calculate_discount(100, 10) == 90

    def test_zero_discount(self):
        assert calculate_discount(100, 0) == 100

    def test_full_discount(self):
        assert calculate_discount(100, 100) == 0

    def test_decimal_discount(self):
        assert calculate_discount(99.99, 15) == 84.9915

    def test_negative_price_raises_error(self):
        with pytest.raises(ValueError):
            calculate_discount(-10, 5)

    def test_invalid_discount_raises_error(self):
        with pytest.raises(ValueError):
            calculate_discount(100, 110)

# Run tests: pytest test_calculator.py -v

# Test-Driven Development (TDD) Example
# File: test_account.py and account.py

# === STEP 1: Write tests first (RED - tests fail) ===
# File: test_account.py
import pytest
from account import BankAccount

class TestBankAccount:
    def test_create_account_with_initial_balance(self):
        account = BankAccount("John Doe", 1000)
        assert account.balance == 1000

    def test_deposit_increases_balance(self):
        account = BankAccount("John Doe", 1000)
        account.deposit(500)
        assert account.balance == 1500

    def test_withdraw Decreases_balance(self):
        account = BankAccount("John Doe", 1000)
        account.withdraw(300)
        assert account.balance == 700

    def test_withdraw_insufficient_funds_raises_error(self):
        account = BankAccount("John Doe", 100)
        with pytest.raises(ValueError):
            account.withdraw(200)

    def test_transfer_between_accounts(self):
        account1 = BankAccount("Alice", 1000)
        account2 = BankAccount("Bob", 500)
        account1.transfer(account2, 300)
        assert account1.balance == 700
        assert account2.balance == 800

# === STEP 2: Implement code to pass tests (GREEN) ===
# File: account.py
class BankAccount:
    def __init__(self, holder_name, initial_balance):
        if initial_balance < 0:
            raise ValueError("Initial balance cannot be negative")
        self.holder_name = holder_name
        self.balance = initial_balance

    def deposit(self, amount):
        if amount <= 0:
            raise ValueError("Deposit amount must be positive")
        self.balance += amount

    def withdraw(self, amount):
        if amount <= 0:
            raise ValueError("Withdrawal amount must be positive")
        if amount > self.balance:
            raise ValueError("Insufficient funds")
        self.balance -= amount

    def transfer(self, other_account, amount):
        self.withdraw(amount)
        other_account.deposit(amount)

# Run: pytest test_account.py -v

# Property-Based Testing with Hypothesis
# Advanced Quality Assurance Technique
# File: test_properties.py

from hypothesis import given, settings, assume, example
import hypothesis.strategies as st

# Function under test - String processing
def validate_email(email):
    """Validate email format"""
    if not email or '@' not in email:
        return False
    local, domain = email.rsplit('@', 1)
    if not local or not domain:
        return False
    if '.' not in domain:
        return False
    return True

def process_username(username):
    """Normalize username"""
    return username.strip().lower().replace(' ', '_')

# Property-based tests
class TestWithHypothesis:

    @given(emails=st.lists(st.emails(), min_size=1, max_size=100))
    def test_email_validation_never_crashes(self, emails):
        """Property: Function should never raise exceptions"""
        for email in emails:
            try:
                validate_email(email)
            except Exception as e:
                pytest.fail(f"Function crashed on {email}: {e}")

    @given(st.text(alphabet=st.characters(whitelist_categories=['L', 'N']), min_size=1))
    def test_username_normalization_idempotent(self, username):
        """Property: Processing twice should equal processing once (idempotent)"""
        result1 = process_username(username)
        result2 = process_username(result1)
        assert result1 == result2

    @given(text=st.text(min_size=1))
    def test_username_not_empty(self, text):
        """Property: Processed username should never be empty if input is non-empty"""
        assume(len(text.strip()) > 0)
        result = process_username(text)
        assert len(result) > 0

    @given(name=st.text(min_size=2))
    def test_username_contains_no_leading_trailing(self, name):
        """Property: Processed username should have no leading/trailing spaces"""
        assume(len(name.strip()) > 0)
        result = process_username(name)
        assert result == result.strip()

# Run: pytest test_properties.py -v --hypothesis-show-statistics
